/**
 * Script to create test fixture images for E2E tests
 * 
 * This creates simple colored JPEG images that can be used for testing
 * photo upload functionality in case creation tests.
 * 
 * Usage: node tests/fixtures/create-test-images.js
 */

const fs = require('fs');
const path = require('path');

// Create a simple 1x1 pixel JPEG image (base64 encoded)
// This is a minimal valid JPEG file
const createMinimalJpeg = (color) => {
  // Minimal JPEG header + single pixel data
  // This creates a valid but tiny JPEG file
  const jpegData = Buffer.from([
    0xFF, 0xD8, 0xFF, 0xE0, 0x00, 0x10, 0x4A, 0x46, 0x49, 0x46, 0x00, 0x01,
    0x01, 0x00, 0x00, 0x01, 0x00, 0x01, 0x00, 0x00, 0xFF, 0xDB, 0x00, 0x43,
    0x00, 0x08, 0x06, 0x06, 0x07, 0x06, 0x05, 0x08, 0x07, 0x07, 0x07, 0x09,
    0x09, 0x08, 0x0A, 0x0C, 0x14, 0x0D, 0x0C, 0x0B, 0x0B, 0x0C, 0x19, 0x12,
    0x13, 0x0F, 0x14, 0x1D, 0x1A, 0x1F, 0x1E, 0x1D, 0x1A, 0x1C, 0x1C, 0x20,
    0x24, 0x2E, 0x27, 0x20, 0x22, 0x2C, 0x23, 0x1C, 0x1C, 0x28, 0x37, 0x29,
    0x2C, 0x30, 0x31, 0x34, 0x34, 0x34, 0x1F, 0x27, 0x39, 0x3D, 0x38, 0x32,
    0x3C, 0x2E, 0x33, 0x34, 0x32, 0xFF, 0xC0, 0x00, 0x0B, 0x08, 0x00, 0x01,
    0x00, 0x01, 0x01, 0x01, 0x11, 0x00, 0xFF, 0xC4, 0x00, 0x14, 0x00, 0x01,
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
    0x00, 0x00, 0x00, 0x03, 0xFF, 0xC4, 0x00, 0x14, 0x10, 0x01, 0x00, 0x00,
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
    0x00, 0x00, 0xFF, 0xDA, 0x00, 0x08, 0x01, 0x01, 0x00, 0x00, 0x3F, 0x00,
    0x37, 0xFF, 0xD9
  ]);
  
  return jpegData;
};

const fixturesDir = __dirname;

// Create three test images
const images = [
  { name: 'test-photo-1.jpg', color: 'blue' },
  { name: 'test-photo-2.jpg', color: 'red' },
  { name: 'test-photo-3.jpg', color: 'green' },
];

console.log('Creating test fixture images...\n');

images.forEach(({ name, color }) => {
  const filePath = path.join(fixturesDir, name);
  const jpegData = createMinimalJpeg(color);
  
  fs.writeFileSync(filePath, jpegData);
  console.log(`✓ Created ${name} (${jpegData.length} bytes)`);
});

console.log('\nTest fixture images created successfully!');
console.log('You can now run E2E tests that require photo uploads.');
